 362→#### 维度 4：参数校验
 363→```javascript
 364→async function testParamValidation() {
 365→  console.log('\n🔒 参数校验');
 366→
 367→  // 每个列表接口都要测，不只测一个
 368→  const endpoints = ['/listXxx', '/listYyy', '/listZzz'];
 369→  for (const ep of endpoints) {
 370→    const r1 = await GET(`${ep}?pageNo=0&pageSize=20`);
 371→    assert(`${ep} pageNo=0 应返回错误`, r1.success === false);
 372→
 373→    const r2 = await GET(`${ep}?pageNo=-1&pageSize=20`);
 374→    assert(`${ep} pageNo=-1 应返回错误`, r2.success === false);
 375→
 376→    const r3 = await GET(`${ep}?pageNo=1&pageSize=0`);
 377→    assert(`${ep} pageSize=0 应返回错误`, r3.success === false);
 378→
 379→    const r4 = await GET(`${ep}?pageNo=1&pageSize=101`);
 380→    assert(`${ep} pageSize=101 应返回错误`, r4.success === false);
 381→
 382→    const r5 = await GET(`${ep}?pageNo=1&pageSize=-1`);
 383→    assert(`${ep} pageSize=-1 应返回错误`, r5.success === false);
 384→  }
 385→
 386→  // POST 接口缺少必填字段
 387→  const noField1 = await POST('/editXxx', { /* 缺少必填字段 */ });
 388→  assert('缺少必填字段返回错误', noField1.success === false);
 389→}
 390→```
