 392→#### 维度 5：特殊字符与注入防护
 393→```javascript
 394→async function testInjectionAndSpecialChars() {
 395→  console.log('\n🛡️ 注入防护 + 特殊字符');
 396→
 397→  // 特殊字符
 398→  const specialChars = ['%', '_', '\'', '"', '\\', '<script>', '&&', '||'];
 399→  for (const ch of specialChars) {
 400→    const res = await GET(`/listXxx?keyword=${encodeURIComponent(ch)}&pageNo=1&pageSize=20`);
 401→    assert(`特殊字符 "${ch}" 不报500`,
 402→      res.success === true || (res.code && res.code !== 500));
 403→  }
 404→
 405→  // SQL 注入
 406→  const injections = [
 407→    "' OR 1=1 --",
 408→    "1; DROP TABLE xxx;",
 409→    "' UNION SELECT * FROM users --",
 410→    "1' AND '1'='1",
 411→    "admin'/*",
 412→  ];
 413→  for (const payload of injections) {
 414→    const res = await GET(`/listXxx?keyword=${encodeURIComponent(payload)}&pageNo=1&pageSize=20`);
 415→    assert(`注入 "${payload.slice(0, 25)}..." 不报500`,
 416→      res.success === true || (res.code && res.code !== 500));
 417→  }
 418→
 419→  // 超长字符串
 420→  const longStr = 'a'.repeat(200);
 421→  const longRes = await GET(`/listXxx?keyword=${encodeURIComponent(longStr)}&pageNo=1&pageSize=20`);
 422→  assert('超长 keyword 不报错',
 423→    longRes.success === true || (longRes.code && longRes.code !== 500));
 424→}
 425→```
