 427→#### 维度 6：写操作验证
 428→```javascript
 429→async function testWriteAndVerify() {
 430→  console.log('\n⚡ 写操作验证');
 431→
 432→  // 1. 读取原始状态
 433→  const before = await GET('/listXxx?pageNo=1&pageSize=1');
 434→  const original = before.data?.records?.[0];
 435→  if (!original) { console.log('  ⚠️ 无数据，跳过'); return; }
 436→  const originalValue = original.role;
 437→  const newValue = originalValue === 'reader' ? 'editor' : 'reader';
 438→
 439→  // 2. 记录日志数量
 440→  const logsBefore = await GET('/logs?pageNo=1&pageSize=1');
 441→  const totalBefore = logsBefore.data?.total || 0;
 442→
 443→  // 3. 执行写操作
 444→  const editRes = await POST('/editXxx', { id: original.id, role: newValue });
 445→  assert('写操作返回 success', editRes.success === true);
 446→
